variable "worker_count" {
  type    = number
  default = 4
}

variable "instance_type" {
  type    = string
  default = "p4d.24xlarge"
}

variable "environment" {
  type    = string
  default = "dev"
}

resource "aws_placement_group" "gpu_cluster" {
  name     = "gpu-cluster-${var.environment}"
  strategy = "cluster"
}

resource "aws_instance" "gpu_worker" {
  count             = var.worker_count
  ami               = "ami-0abcdef1234567890"
  instance_type     = var.instance_type
  placement_group   = aws_placement_group.gpu_cluster.id

  root_block_device {
    volume_size = 500
    volume_type = "gp3"
  }

  tags = {
    Name        = "gpu-worker-${count.index}"
    Environment = var.environment
  }
}

resource "aws_efs_file_system" "shared_data" {
  performance_mode = "maxIO"
  throughput_mode  = "elastic"
  encrypted        = true
  tags = { Name = "training-data-${var.environment}" }
}

from kfp import dsl
from kfp.dsl import Input, Output, Dataset, Model, Metrics

@dsl.component(base_image="python:3.11-slim", packages_to_install=["pandas"])
def data_preprocess(raw_path: str, processed: Output[Dataset]):
    import pandas as pd
    df = pd.read_parquet(raw_path)
    df = df.dropna().reset_index(drop=True)
    df.to_parquet(processed.path)

@dsl.component(base_image="nvcr.io/nvidia/pytorch:24.01-py3")
def train_model(data: Input[Dataset], epochs: int, model_out: Output[Model]):
    import torch
    model = build_model()
    train(model, data.path, epochs)
    torch.save(model.state_dict(), model_out.path)

@dsl.component(base_image="nvcr.io/nvidia/pytorch:24.01-py3")
def evaluate_model(model: Input[Model], data: Input[Dataset], metrics: Output[Metrics]):
    accuracy = run_evaluation(model.path, data.path)
    metrics.log_metric("accuracy", accuracy)

@dsl.pipeline(name="training-pipeline")
def pipeline(raw_data: str, epochs: int = 10):
    prep = data_preprocess(raw_path=raw_data)
    train_task = train_model(data=prep.outputs["processed"], epochs=epochs)
    train_task.set_gpu_limit(8).set_memory_limit("128Gi")
    eval_task = evaluate_model(
        model=train_task.outputs["model_out"],
        data=prep.outputs["processed"]
    )
    eval_task.set_gpu_limit(1)

name: "bert_classifier"
platform: "onnxruntime_onnx"
max_batch_size: 64

input [{
  name: "input_ids"
  data_type: TYPE_INT64
  dims: [256]
}, {
  name: "attention_mask"
  data_type: TYPE_INT64
  dims: [256]
}]

output [{
  name: "class_probabilities"
  data_type: TYPE_FP32
  dims: [5]
}]

dynamic_batching {
  preferred_batch_size: [8, 32]
  max_queue_delay_microseconds: 150
  preserve_ordering: true
}

instance_group [{
  count: 2
  kind: KIND_GPU
}]
